INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 26, 0, 'Dành 1 giờ cho bất kỳ hình thức sáng tạo offline nào: viết lách, vẽ tranh, nấu ăn, làm đồ thủ công.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 26, 1, 'Không tìm kiếm hướng dẫn online — dùng kiến thức và trực giác hiện có của bản thân.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 26, 2, 'Ghi nhận cảm xúc khi tạo ra điều gì đó "chưa hoàn hảo" so với các nội dung "hoàn hảo" trên mạng.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 26, 3, 'Trực tiếp chia sẻ sản phẩm sáng tạo với một người bạn ngoài đời thực.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 26, 'Phút sáng tạo thực tế (>= 60)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 26, 'Mức độ hài lòng với sản phẩm');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 26, 'Mức độ so sánh với mạng');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 26, 'Số người thực chia sẻ cùng');
INSERT INTO program_days (day_number, week_number, label) VALUES (27, 4, 'Đóng góp & kết nối ý nghĩa');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 27, 0, 'Làm 1 việc tốt giúp đỡ người khác ngoài đời thực — không chụp ảnh, không chia sẻ lên mạng.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 27, 1, 'Gọi điện hoặc gặp mặt hỏi thăm một người quen đã lâu bạn chưa liên lạc.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 27, 2, 'Viết nhật ký: internet và mạng xã hội đã ảnh hưởng như thế nào đến các mối quan hệ của bạn?');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 27, 3, 'Lên lịch trình gặp gỡ bạn bè, người thân trực tiếp cho tháng tới.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 27, 'Số hành động giúp đỡ thực tế (>= 1)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 27, 'Chất lượng gắn kết');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 27, 'Thời gian kết nối thực tế vs mạng xã hội');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 27, 'Lịch trình gặp gỡ tháng tới');
INSERT INTO program_days (day_number, week_number, label) VALUES (28, 4, 'Nhìn lại hành trình & tích hợp lối sống');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 28, 0, 'Đọc lại toàn bộ nhật ký 28 ngày qua — nhận ra những mô thức hành vi của bản thân.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 28, 1, 'So sánh dữ liệu thực tế: thời gian màn hình ngày 1 so với hôm nay, tâm trạng, giấc ngủ, tập trung.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 28, 2, 'Viết 1 trang chia sẻ về "bản thân tôi trước và sau hành trình 28 ngày này".');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 28, 3, 'Chia sẻ những bài học bổ ích này với người đồng hành hoặc một người bạn tin cậy.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 28, '% cải thiện thời gian màn hình tổng');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 28, 'Cải thiện tâm trạng');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 28, 'Cải thiện giấc ngủ');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 28, 'Số bài học tự rút ra');
INSERT INTO program_days (day_number, week_number, label) VALUES (29, 4, 'Xây dựng Bản cam kết số cá nhân');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 29, 0, 'Viết "Bản cam kết số cá nhân": 5–7 nguyên tắc sử dụng thiết bị số và internet của riêng bạn.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 29, 1, 'Thiết lập ngày nghỉ ngơi số (Digital sabbath): 1 ngày/tuần giảm 90% việc dùng internet.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 29, 2, 'Cài đặt nhắc nhở: xem lại Bản cam kết số vào cuối mỗi tháng.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 29, 3, 'Xác định 1 mục tiêu lớn ngoài đời thực trong 3 tháng tới.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 29, 'Bản cam kết số (Hoàn thiện?)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 29, 'Ngày nghỉ ngơi số đã chọn');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 29, 'Mục tiêu thực tế 3 tháng');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 29, 'Mức độ cam kết (1-10)');
INSERT INTO program_days (day_number, week_number, label) VALUES (30, 4, 'Ăn mừng & Cam kết hành trình tiếp theo');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 30, 0, 'Tổng kết: lưu trữ tất cả dữ liệu theo dõi 30 ngày qua vào 1 cuốn sổ hoặc file cá nhân.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 30, 1, 'Viết một bức thư gửi cho chính mình của 6 tháng sau — kể về hành trình 30 ngày ý nghĩa này.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 30, 2, 'Ăn mừng trực tiếp ngoài đời thực cùng bạn bè/người thân — chia sẻ câu chuyện của bạn.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (1, 4, 30, 3, 'Cam kết: duy trì lối sống lành mạnh trong 66 ngày tiếp theo để thói quen bền vững — đặt lịch nhắc nhở.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 30, 'Hoàn thành 30/30 nhiệm vụ');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 30, 'Báo cáo dữ liệu đã lưu');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 30, 'Thư tương lai đã viết');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (1, 4, 30, 'Cam kết ngày thứ 66');
INSERT INTO program_phases (phase_number, label, range_text, icon, focus, science) VALUES (2, 'Củng Có Nền Tảng', 'Ngày 31–60', '⚡', 'Làm việc sâu, rèn luyện sự thích ứng cảm xúc, tích lũy vốn xã hội thực tế.', 'Hình thành thói quen cần trung bình 66 ngày (Lally et al., 2010); Tính dẻo của não bộ; Ngăn ngừa trượt dốc dựa trên chánh niệm (MBRP).');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (5, 2, 'Làm Việc Tập Trung Sâu', 'Ngày 31–37', 'Tăng thời gian tập trung sâu lên 2-3 giờ/ngày. Xây dựng hệ thống hiệu suất thực tế. Đo lường kết quả công việc, không chỉ đo thời gian.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 5, NULL, 0, 'Thiết kế nghi thức tập trung sâu cá nhân: cùng giờ, cùng địa điểm, cùng tín hiệu khởi động.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 5, NULL, 1, 'Tăng chu kỳ Pomodoro từ 25 lên 50 phút — đo lường sức bền nhận thức thực tế.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 5, NULL, 2, 'Đánh giá kết quả tuần: đã tạo ra sản phẩm gì trong tuần (so với chỉ đọc/xem nội dung)?');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 5, NULL, 3, 'Giảm mạng xã hội xuống ≤ 30 phút/ngày bằng tính năng hẹn giờ giới hạn nghiêm ngặt.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 5, NULL, 'Phút tập trung sâu/ngày (>= 120)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 5, NULL, 'Kết quả tuần (nhiệm vụ/bài/sản phẩm) (>= 3)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 5, NULL, 'Mạng xã hội (phút/ngày) (<= 30)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 5, NULL, 'Chuỗi ngày liên tục (ngày)');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (6, 2, 'Điều Hòa Cảm Xúc', 'Ngày 38–44', 'Xây dựng bộ công cụ điều hòa cảm xúc không phụ thuộc internet. Nhận diện "sự đói cảm xúc" — nhiều lần dùng điện thoại là để lấp đầy khoảng trống cảm xúc, không phải để tìm kiếm thông tin cần thiết.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 6, NULL, 0, 'Ghi nhận tâm trạng hàng daily sáng và tối — theo dõi mô thức cảm xúc theo tuần.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 6, NULL, 1, 'Khi căng thẳng: dùng kỹ thuật dừng lại (Dừng lại, Hít thở, Quan sát, Tiếp tục).');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 6, NULL, 2, 'Xây dựng danh mục giải tỏa cá nhân: 10 hoạt động không internet giúp tinh thần tốt hơn.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 6, NULL, 3, 'Nhờ 3 người thân nhận xét về thay đổi của bạn từ tháng 1 — ghi lại phản hồi.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 6, NULL, 'Nhật ký cảm xúc hoàn thành (Sáng + Tối)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 6, NULL, 'Số lần dùng kỹ thuật dừng lại');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 6, NULL, 'Danh mục giải tỏa hoàn thiện (>= 10)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 6, NULL, 'Phản hồi từ người thân (>= 3 người)');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (7, 2, 'Kết Nối Xã Hội Thực Tế', 'Ngày 45–51', 'Khôi phục và đầu tư vào mối quan hệ thực tế. Nghiên cứu Harvard 80 năm: chất lượng mối quan hệ là yếu tố hàng đầu quyết định sức khỏe và hạnh phúc (Waldinger, 2015).');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 7, NULL, 0, 'Lập "bản đồ mối quan hệ": vẽ vòng tròn thân thiết — người bạn muốn gắn kết hơn.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 7, NULL, 1, 'Đặt lịch gặp mặt trực tiếp ít nhất 2 lần/tuần với người thân/bạn bè.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 7, NULL, 2, 'Bữa ăn không điện thoại: 1 bữa ăn/tuần với gia đình hoặc bạn bè, điện thoại để ngoài phòng.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 7, NULL, 3, 'Tham gia 1 câu lạc bộ, lớp học, hoặc nhóm trực tiếp phù hợp sở thích.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 7, NULL, 'Lần gặp mặt trực tiếp/tuần (>= 2)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 7, NULL, 'Bữa ăn không điện thoại (1/tuần)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 7, NULL, 'Tham gia hoạt động cộng đồng (>= 1/tháng)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 7, NULL, 'Chất lượng mối quan hệ');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (8, 2, 'Đánh Giá & Tái Thiết Lập Tháng', 'Ngày 52–60', 'Tổng kết 60 ngày. Đây là cột mốc quan trọng — bạn đã vượt qua giai đoạn điều chỉnh thử thách nhất. Não bộ đã hình thành các đường truyền thần kinh mới tốt đẹp.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 8, NULL, 0, 'So sánh dữ liệu 60 ngày so với ngày 1: thời gian sử dụng màn hình, chất lượng giấc ngủ, độ tập trung, tâm trạng, các mối quan hệ.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 8, NULL, 1, 'Viết "Thư gửi bản thân trong quá khứ": bạn sẽ nói gì với bản thân 60 ngày trước?');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 8, NULL, 2, 'Điều chỉnh Bản cam kết số cá nhân dựa trên những gì đã học.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (2, 8, NULL, 3, 'Tự thưởng: tổ chức sự kiện thực tế có ý nghĩa — chuyến đi ngắn, bữa ăn đặc biệt, trải nghiệm mới.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 8, NULL, '% giảm thời gian màn hình so với ngày 1');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 8, NULL, 'Cải thiện chất lượng ngủ');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 8, NULL, 'Cải thiện thời gian tập trung');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (2, 8, NULL, 'Mức độ hài lòng trong mối quan hệ');
INSERT INTO program_phases (phase_number, label, range_text, icon, focus, science) VALUES (3, 'Tích Hợp Lối Sống', 'Ngày 61–90', '🧭', 'Định hình bản sắc cá nhân mới, phát triển sáng tạo, tối ưu hóa năng lượng thể chất.', 'Thay đổi thói quen dựa trên bản sắc (James Clear, 2018); Thuyết tự quyết (Deci & Ryan, 2000).');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (9, 3, 'Định Hình Bản Sắc Mới', 'Ngày 61–67', 'Cuộc sống làm chủ bản thân không chỉ đơn thuần là "bỏ thói quen cũ" — đó là sống theo một bản sắc mới tích cực. Giai đoạn này tập trung vào "tôi là người như thế nào" thay vì chỉ là "tôi làm gì".');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 9, NULL, 0, 'Viết "Cẩm nang về tôi": bạn là ai, bạn trân trọng giá trị gì, bạn muốn sống cuộc đời như thế nào?.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 9, NULL, 1, 'Chọn 1 tuyên ngôn bản sắc: "Tôi là người..." và thử thách nó trong mọi quyết định hàng ngày.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 9, NULL, 2, 'Xem xét lại mọi ứng dụng trên điện thoại: cái nào phục vụ bản sắc mới, cái nào đi ngược lại?.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 9, NULL, 3, 'Hỏi trước mỗi lần sử dụng internet: "Điều này có phục vụ cho người mà tôi mong muốn trở thành?"');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 9, NULL, 'Cẩm nang về tôi hoàn thiện');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 9, NULL, 'Áp dụng tuyên ngôn bản sắc/ngày');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 9, NULL, 'Ứng dụng phù hợp bản sắc');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 9, NULL, 'Câu hỏi trước khi sử dụng internet');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (10, 3, 'Sáng Tạo & Ý Nghĩa', 'Ngày 68–74', 'Khi não bộ không còn bị kích thích liên tục bởi thế giới ảo, tư duy sáng tạo tự nhiên sẽ trỗi dậy mạnh mẽ.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 10, NULL, 0, 'Trang viết buổi sáng: viết tự do 3 trang mỗi sáng trước khi làm bất kỳ việc gì (Julia Cameron).');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 10, NULL, 1, 'Bắt đầu 1 dự án sáng tạo dài hạn trực tiếp — 30 phút/ngày.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 10, NULL, 2, 'Chủ đề viết nhật ký: "Nếu không có gì cản trở, tôi thực sự mong muốn làm gì?".');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 10, NULL, 3, 'Ghi lại mọi ý tưởng nảy sinh trong ngày vào sổ tay giấy.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 10, NULL, 'Ngày viết trang sáng (>= 5/7)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 10, NULL, 'Phút làm dự án sáng tạo/ngày (>= 30)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 10, NULL, 'Số ý tưởng ghi nhận/tuần');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 10, NULL, 'Độ sáng tạo tự cảm nhận');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (11, 3, 'Tối Ưu Hóa Thể Chất', 'Ngày 75–81', 'Não bộ và cơ thể là một hệ thống thống nhất. Đây là lúc nâng cấp toàn diện: giấc ngủ sâu hơn, thể thao có định hướng, dinh dưỡng hỗ trợ khả năng thích ứng thần kinh.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 11, NULL, 0, 'Đồng bộ giờ ngủ/thức: cùng một mốc thời gian 7 ngày/tuần ± 30 phút kể cả cuối tuần.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 11, NULL, 1, 'Tập luyện có cấu trúc: tập tim mạch 3 lần/tuần + tập sức mạnh 2 lần/tuần.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 11, NULL, 2, 'Dinh dưỡng brain: omega-3, việt quất, sô-cô-la đen, trà xanh — bổ sung vào thực đơn hàng ngày.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 11, NULL, 3, 'Tắm nước lạnh 30–60 giây cuối mỗi buổi tắm — tăng các chất dẫn truyền thần kinh hạnh phúc tự nhiên.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 11, NULL, 'Giờ ngủ/thức ổn định (± 30 phút)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 11, NULL, 'Ngày tập luyện/tuần (>= 4)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 11, NULL, 'Chất lượng giấc ngủ (1-10)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 11, NULL, 'Năng lượng buổi sáng');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (12, 3, 'Cột Mốc 90 Ngày & Kế Hoạch', 'Ngày 82–90', '90 ngày là điểm tựa quan trọng trong mọi chương trình phục hồi thói quen. Tại đây bạn có dữ liệu và trải nghiệm thực tế để tự đánh giá và lập kế hoạch cho 6-12 tháng tiếp theo.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 12, NULL, 0, 'Đánh giá toàn diện 90 ngày: so sánh 15 chỉ số từ ngày 1 đến hôm nay.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 12, NULL, 1, 'Viết "Câu chuyện 90 ngày": hành trình của bạn từ ngày đầu đến hôm nay — 1-2 trang.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 12, NULL, 2, 'Chia sẻ câu chuyện với ít nhất 3 người — trực tiếp để tăng kết nối thực tế.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (3, 12, NULL, 3, 'Lập kế hoạch năm: bạn muốn làm gì với thời gian và năng lượng dồi dào đã tích lũy được?');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 12, NULL, 'Đánh giá 90 ngày hoàn thành');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 12, NULL, '15 chỉ số đã so sánh');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 12, NULL, 'Người đã chia sẻ câu chuyện (>= 3)');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (3, 12, NULL, 'Kế hoạch năm');
INSERT INTO program_phases (phase_number, label, range_text, icon, focus, science) VALUES (4, 'Làm Chủ Hoàn Toàn', 'Ngày 91–120', '🏆', 'Phong cách tối giản số bền vững, tầm nhìn cuộc sống dài hạn, cống hiến và để lại giá trị lâu dài.', 'Mô hình PERMA về hạnh phúc bền vững (Seligman, 2011); Thuyết dòng chảy; Lối sống tối giản số (Newport, 2019).');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (13, 4, 'Thiết Kế Tối Giản Số', 'Ngày 91–97', 'Không phải là ngắt kết nối mãi mãi mà là thiết kế lại mối quan hệ của bạn với công nghệ một cách có chủ đích. Tối giản số không phải chống lại công nghệ mà là định hình cách dùng công nghệ phục vụ cuộc sống của bạn.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 13, NULL, 0, 'Kiểm kê toàn bộ đời sống số: ứng dụng, đăng ký dịch vụ, danh sách email, tài khoản mạng xã hội — giữ gì, xóa gì?.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 13, NULL, 1, 'Thiết kế "Bản thiết kế đời sống số": công nghệ nào sẽ dùng, dùng vào mục đích gì, trong bao lâu.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 13, NULL, 2, 'Thử thách 30 ngày không công nghệ tùy chọn: tạm ngưng thêm 1 nền tảng không cần thiết.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 13, NULL, 3, 'Đọc hoặc nghe cuốn "Lối sống tối giản thời công nghệ số" của Cal Newport — áp dụng 3 nguyên tắc cốt lõi.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 13, NULL, 'Số ứng dụng/tài khoản đã xóa');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 13, NULL, 'Bản thiết kế đời sống số hoàn thiện');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 13, NULL, 'Nền tảng thử nghiệm loại bỏ');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 13, NULL, 'Nguyên tắc áp dụng');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (14, 4, 'Mục Tiêu & Tầm Nhìn Dài Hạn', 'Ngày 98–104', 'Sử dụng internet quá mức thường để khỏa lấp khoảng trống về mục tiêu sống. Khi bạn có lý tưởng và kế hoạch rõ ràng, thế giới ảo tự khắc giảm sức hút bởi bạn đang có những việc quan trọng hơn cần hoàn thành.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 14, NULL, 0, 'Thực hành Ikigai: vẽ 4 vòng tròn lý tưởng (điều bạn yêu thích / điều bạn giỏi / điều thế giới cần / điều mang lại thu nhập).');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 14, NULL, 1, 'Viết tầm nhìn 1 năm: trong 12 tháng nữa bạn mong muốn đạt được những cột mốc nào?.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 14, NULL, 2, 'Lập kế hoạch ngược: từ tầm nhìn 1 năm, phân bổ thành mục tiêu 3 tháng, 1 tháng, 1 tuần.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 14, NULL, 3, 'Xác định 1 "Dự án lớn" để dành 1 giờ mỗi ngày tập trung thực hiện trong 90 ngày tới.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 14, NULL, 'Ikigai hoàn thành');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 14, NULL, 'Tầm nhìn 1 năm đã viết');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 14, NULL, 'Mục tiêu ngược đã phân bổ');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 14, NULL, 'Dự án lớn đã chọn');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (15, 4, 'Đóng Góp & Giá Trị Bền Vững', 'Ngày 105–111', 'Hạnh phúc đích thực đến từ sự sẻ chia — đóng góp giá trị cho người khác và cộng đồng. Đây là đỉnh cao của tháp hạnh phúc và là yếu tố bảo vệ vững chắc nhất giúp bạn duy trì lối sống lành mạnh lâu dài.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 15, NULL, 0, 'Tìm 1 cách đóng góp cho cộng đồng phù hợp với năng lực và giá trị của bạn.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 15, NULL, 1, 'Tình nguyện hoặc làm người hướng dẫn: dạy cho người khác một điều bạn thành thạo — trực tiếp, ngoài đời thực.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 15, NULL, 2, 'Chia sẻ hành trình hơn 90 ngày qua với một người đang cần: trò chuyện chân thành, không chia sẻ lên mạng xã hội.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 15, NULL, 3, 'Viết "Tuyên ngôn cống hiến": tôi muốn đóng góp giá trị gì cho thế giới xung quanh?.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 15, NULL, 'Hoạt động cống hiến đã thực hiện');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 15, NULL, 'Người được hỗ trợ/hướng dẫn');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 15, NULL, 'Người đã chia sẻ hành trình');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 15, NULL, 'Tuyên ngôn cống hiến');
INSERT INTO program_weeks (week_number, phase_number, label, range_text, description) VALUES (16, 4, 'Đánh Giá 120 Ngày & Lối Sống Trọn Đời', 'Ngày 112–120', 'Đây không phải là điểm kết thúc — đây là nền móng. 120 ngày là khoảng thời gian đủ để não bộ thay đổi cấu trúc tích cực, giúp bạn nhận diện rõ ràng bản thân khi không bị xao nhãng bởi thế giới số.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 16, NULL, 0, 'Đánh giá dữ liệu toàn diện 120 ngày: tổng hợp tất cả các chỉ số theo dõi trong 4 tháng.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 16, NULL, 1, 'Viết "Tuyên ngôn cá nhân": các nguyên tắc sống cốt lõi của bạn — không chỉ là quy tắc sử dụng thiết bị số mà là kim chỉ nam cuộc sống.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 16, NULL, 2, 'Thiết lập hệ thống duy trì trọn đời: đánh giá hàng tháng, điều chỉnh hàng quý, tái cân bằng hàng năm.');
INSERT INTO program_tasks_metadata (phase_number, week_number, day_number, task_index, title) VALUES (4, 16, NULL, 3, 'Tự thưởng và tri ân: thực hiện một điều ý nghĩa cùng những người bạn yêu thương.');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 16, NULL, 'Đánh giá dữ liệu 120 ngày');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 16, NULL, 'Tuyên ngôn cá nhân đã viết');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 16, NULL, 'Hệ thống trọn đời đã thiết lập');
INSERT INTO program_metrics_metadata (phase_number, week_number, day_number, metric_name) VALUES (4, 16, NULL, 'Hoạt động tự thưởng đã lên kế hoạch');